mapper.select:
select cpm.*, party.user_id , party.user_code , party.user_name from t_c2c_payment_method cpm left join tz_user party on cpm.party_id = party.user_id left join t_c2c_user cu on cu.c2c_user_party_id = party.user_id where 1 = 1 and cpm.type=#{type}
and cu.c2c_manager_party_id=#{loginPartyId}
AND (party.user_name like CONCAT('%', #{userCode}, '%') or party.user_code like CONCAT('%', #{userCode}, '%'))
and cpm.method_type =${methodType}
and cpm.method_name like CONCAT('%', #{methodName}, '%')
order by cpm.create_time desc
